<template><div class="page-container"><div class="page-card"><div class="page-header"><span class="page-title">徽章头衔</span><a-button type="primary" @click="onCreate"><plus-outlined/>新建徽章</a-button></div><DataTable :columns="cols" :data-source="list" :loading="ld" :total="t" v-model:page="p" v-model:page-size="ps"><template #icon="{r}"><a-image :src="r.icon" :width="40" :height="40" style="border-radius:4px"/></template><template #a="{r}"><a-space><a @click="onEdit(r)">编辑</a><a-popconfirm title="确定删除?" @confirm="onDel(r.id)"><a style="color:#ef4444">删除</a></a-popconfirm></a-space></template></DataTable></div></div></template>
<script setup lang="ts">import {ref} from 'vue';import {message} from 'ant-design-vue';import {PlusOutlined} from '@ant-design/icons-vue';import {marketingApi} from '@/api/marketing';import DataTable from '@/components/common/DataTable.vue'
const ld=ref(false),list=ref<any[]>([]),t=ref(0),p=ref(1),ps=ref(20);const cols=[{title:'图标',dataIndex:'icon',width:60,slot:'icon'},{title:'名称',dataIndex:'name',width:150},{title:'描述',dataIndex:'description'},{title:'类型',dataIndex:'type',width:90},{title:'积分奖励',dataIndex:'points',width:80},{title:'操作',dataIndex:'action',width:100,slot:'a'}]
async function ft(){ld.value=true;try{const r=await marketingApi.getBadgeList({page:p.value,pageSize:ps.value});list.value=r.data.data?.list||r.data?.list||[];t.value=r.data.data?.total||0}catch{}finally{ld.value=false}}
function onCreate(){message.info('新建徽章')};function onEdit(_:any){message.info('编辑')};async function onDel(id:number){await marketingApi.deleteBadge(id);message.success('已删除');ft()}
ft();
</script>
